"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[540017],{995396:e=>{e.exports=JSON.parse('{"tag":{"label":"data","permalink":"/dst-api-webdocs/docs/tags/data","allTagsPath":"/dst-api-webdocs/docs/tags","count":28,"items":[{"id":"game-scripts/achievements","title":"Achievements","description":"Defines the list of achievements available in the game, mapping internal names to platform-specific identifiers.","permalink":"/dst-api-webdocs/docs/game-scripts/achievements"},{"id":"game-scripts/components/boatringdata","title":"Boatringdata","description":"Stores and synchronizes visual ring configuration data for boat-related effects, including radius, segment count, and rotation state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatringdata"},{"id":"game-scripts/clothing","title":"Clothing","description":"A static data registry defining clothing items, their visual overrides, hide layers, and associated sounds/symbols used by the game\'s rendering and UI systems.","permalink":"/dst-api-webdocs/docs/game-scripts/clothing"},{"id":"game-scripts/components/dataanalyzer","title":"Dataanalyzer","description":"Manages creature data collection, regeneration, and consumption for scanner-like entities in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dataanalyzer"},{"id":"game-scripts/datagrid","title":"Datagrid","description":"A utility class for managing a 2D grid of data stored in a 1D Lua table, supporting coordinate-to-index conversion and basic persistence operations.","permalink":"/dst-api-webdocs/docs/game-scripts/datagrid"},{"id":"game-scripts/emoji_items","title":"Emoji Items","description":"Defines a global lookup table of emoji item definitions with metadata for in-game use.","permalink":"/dst-api-webdocs/docs/game-scripts/emoji_items"},{"id":"game-scripts/prefabs/farm_plant_defs","title":"Farm Plant Defs","description":"Provides plant definition data used by the farming system to configure growth, moisture, season, nutrient, and other gameplay properties for each crop.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_plant_defs"},{"id":"game-scripts/components/maprecorder","title":"Maprecorder","description":"Stores and manages recorded map data for teaching exploration progress between players.","permalink":"/dst-api-webdocs/docs/game-scripts/components/maprecorder"},{"id":"game-scripts/prefabs/mapscroll","title":"Mapscroll","description":"Represents a map scroll item that records and displays map data, supporting both overworld and cave locations with dynamic description and visual updates.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mapscroll"},{"id":"game-scripts/motdmanager","title":"Motdmanager","description":"Manages downloading, caching, and displaying MOTD (Message of the Day) data\u2014including patch notes, skins, news, and Twitch content\u2014for the DST client.","permalink":"/dst-api-webdocs/docs/game-scripts/motdmanager"},{"id":"game-scripts/components/playeravatardata","title":"Playeravatardata","description":"Manages player avatar data including name, skins, age, and equipment, with support for network replication and save/load operations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playeravatardata"},{"id":"game-scripts/map/static_layouts/events/quagmire_kitchen","title":"Quagmire Kitchen","description":"Provides map data structure for Quagmire kitchen layouts with no runtime logic or entity behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/events/quagmire_kitchen"},{"id":"game-scripts/recipes_filter","title":"Recipes Filter","description":"Defines and organizes crafting menu filters for categorizing recipes by type, character, season, and other criteria.","permalink":"/dst-api-webdocs/docs/game-scripts/recipes_filter"},{"id":"game-scripts/util/savedata","title":"Savedata","description":"Base utility class for loading, saving, and erasing persistent player or world data to disk using TheSim\'s API.","permalink":"/dst-api-webdocs/docs/game-scripts/util/savedata"},{"id":"game-scripts/scrapbook_prefabs","title":"Scrapbook Prefabs","description":"Defines a static list of prefabs to include or exclude from the scrapbook and achievement visibility filtering.","permalink":"/dst-api-webdocs/docs/game-scripts/scrapbook_prefabs"},{"id":"game-scripts/screens/redux/scrapbookdata","title":"Scrapbookdata","description":"Static data registry defining scrapbook entries for items, creatures, and structures used in the in-game scrapbook UI.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/scrapbookdata"},{"id":"game-scripts/scrapbookpartitions","title":"Scrapbookpartitions","description":"Manages chunked storage and logic for the scrapbook data system, including tracking what items each character has seen or inspected, and coordinating with the backend for persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/scrapbookpartitions"},{"id":"game-scripts/skin_set_info","title":"Skin Set Info","description":"A data-only module that maps emote or costume identifiers to lists of associated skin asset names.","permalink":"/dst-api-webdocs/docs/game-scripts/skin_set_info"},{"id":"game-scripts/speech_walter","title":"Speech Walter","description":"A self-contained speech database for the Walter character that maps interaction events to localized string values, used elsewhere in the codebase.","permalink":"/dst-api-webdocs/docs/game-scripts/speech_walter"},{"id":"game-scripts/speech_wanda","title":"Speech Wanda","description":"A static data file providing speech string constants for the character Wanda in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/speech_wanda"},{"id":"game-scripts/speech_wendy","title":"Speech Wendy","description":"A data-only module containing Wendy-specific speech strings for items, structures, and entities across Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/speech_wendy"},{"id":"game-scripts/speech_wx78","title":"Speech Wx78","description":"Provides static speech data and localization strings for the Wx78 character across various DST content and entities.","permalink":"/dst-api-webdocs/docs/game-scripts/speech_wx78"},{"id":"game-scripts/components/symbolswapdata","title":"Symbolswapdata","description":"Stores and manages symbol-swapping configuration data for world symbols (e.g., for map generation or prefabs).","permalink":"/dst-api-webdocs/docs/game-scripts/components/symbolswapdata"},{"id":"game-scripts/techtree","title":"Techtree","description":"Defines and manages available technology trees and associated bonus/level naming conventions for crafting systems.","permalink":"/dst-api-webdocs/docs/game-scripts/techtree"},{"id":"game-scripts/prefabs/tree_rock_data","title":"Tree Rock Data","description":"Provides configuration data for loot tables and biome-specific drop mechanics for tree rock entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tree_rock_data"},{"id":"game-scripts/components/weighable","title":"Weighable","description":"Manages weight-related data and tags for entities that can be weighed (e.g., trophies, items used in weighing mechanics), including owner information and weight percentage calculation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/weighable"},{"id":"game-scripts/worldgen_main","title":"Worldgen Main","description":"Entry point for world generation, responsible for initializing the world generation pipeline, handling mod data, and producing saveable world data structures.","permalink":"/dst-api-webdocs/docs/game-scripts/worldgen_main"},{"id":"game-scripts/prefabs/writeable_classified","title":"Writeable Classified","description":"Serves as a client-side helper entity that coordinates with its parent writeable item to manage classified data attachment and lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/writeable_classified"}],"unlisted":false}}')}}]);